methods.moveTo:
bool Piece::moveTo(Player& byPlayer, Square& toSquare)
{
    bool validMove = false;
    Piece* toCapture = NULL;
    Square* fromSquare = _square;

    // check if this is being moved by its player
    if(_isWhite == byPlayer.isWhite())
    {
        // check if this is moving according to the correct geometry
        if(canMoveTo(toSquare))
        {
            // check if toSquare is occupied by a piece that could be captured
            if(toSquare.occupied())
            {
                toCapture = toSquare.occupiedBy();

                // move only valid if piece to capture is of different color
                if(toCapture->isWhite() != byPlayer.isWhite())
                {
                    validMove = true;
                }
            }
            // if there isn't a capture and we've made it this far, the move is valid
            else 
            {
                validMove = true;
            }

            if(validMove)
            {
                // tentatively make the move:
                // tentatively take opponent's piece off the board, if needed
                if(toCapture)
                {
                    toCapture->setLocation(NULL);
                } 

                // unset this piece's current square's occupant
                _square->setOccupier(NULL);

                // set this piece's new location
                _square = &toSquare;

                // set new square's occupant
                _square->setOccupier(this);

                // check if the move leaves byPlayer's king in check
                if(byPlayer.inCheck())
                {
                    // if in check, move is invalid
                    validMove = false;

                    // undo the move:
                    // reset this piece's location
                    _square = fromSquare;

                    // update the square's occupant
                    _square->setOccupier(this);

                    // reset the other square's occupant with opponent's piece or NULL
                    toSquare.setOccupier(toCapture);

                    // if a piece was tentatively captured, put it back
                    if(toCapture)
                    {
                        toCapture->setLocation(&toSquare);
                    }
                }
                else 
                {
                    // if not in check, move is valid, so actually
                    // capture the opponent's piece, if needed
                    if(toCapture)
                    {
                        byPlayer.capture(toCapture);
                    } 
                }
            }
        }
    }

    return validMove;
}

methods.makeMove:
bool Player::makeMove()
{
    string badInput; // string for throwing away invalid input
    string fromSquare =  "  ";
    string toSquare = "  ";
    int fromX;
    int fromY;
    int toX;
    int toY;

    // check/announce if player is in check
    if(inCheck())
    {
        cout << _name << " is in check!" << endl;
    }

    // get move from player input
    cout << _name << " player enter move (e.g. a2 a4): ";
    cin >> fromSquare >> toSquare;

    // move must be in algebraic notation 
    // (start and end squares denoted by 2 characters, a1-h8,
    // and separated from each other by whitespace)
    // move cannot start from an empty square
    while(fromSquare.length() != 2 ||
          toSquare.length() != 2 ||
          tolower(fromSquare.at(0)) < X_MIN ||
          tolower(fromSquare.at(0)) > X_MAX ||
          tolower(toSquare.at(0)) < X_MIN ||
          tolower(toSquare.at(0)) > X_MAX ||
          tolower(fromSquare.at(1)) < Y_MIN ||
          tolower(fromSquare.at(1)) > Y_MAX ||
          tolower(toSquare.at(1)) < Y_MIN ||
          tolower(toSquare.at(1)) > Y_MAX ||
          !(Board::getBoard()->squareAt(tolower(fromSquare.at(0)) - X_MIN, 
                                      tolower(fromSquare.at(1)) - Y_MIN)->occupied())
          )
    {
        cerr << "Invalid move. Try again." << endl;
        cin.clear();
        getline(cin, badInput); // take bad input off the stream and ignore it
        cout << _name << " player enter move (e.g. a2 a4): ";
        cin >> fromSquare >> toSquare;
    }

    // translate input (algebraic notation) into board coordinates
    fromX = tolower(fromSquare.at(0)) - X_MIN;
    fromY = tolower(fromSquare.at(1)) - Y_MIN;
    toX = tolower(toSquare.at(0)) - X_MIN;
    toY = tolower(toSquare.at(1)) - Y_MIN;

    // move the piece on fromSquare to toSquare
    return Board::getBoard()->squareAt(fromX, fromY)->occupiedBy()->moveTo(*this, 
                                                                  *(Board::getBoard()->squareAt(toX, toY)));
}

methods.inCheck:
bool Player::inCheck()
{
    bool check = false;

    // for each piece in the opponent's set of pieces
    for (set<Piece*>::iterator itr = Game::opponentOf(*this)->myPieces()->begin(); 
         itr != Game::opponentOf(*this)->myPieces()->end(); ++itr)
    {
        // if a piece that is still located on the board
        // can move to my king's square
        if (((Piece*)*itr)->location() && 
            ((Piece*)*itr)->canMoveTo(*(myKing()->location())))
        {
            // I am in check
            check = true;
        }
    }

    return check;
}

methods.capture:
void Player::capture(Piece* aPiece)
{
    // unset the piece's location on the board
    aPiece->setLocation(NULL);

    // put the piece into this player's set of captured pieces
    _capturedPieces.insert(aPiece);
}

methods.score:
int Player::score() const
{
    int score = 0;

    // add up the points of all captured pieces
    for (set<Piece*>::iterator itr = _capturedPieces.begin(); itr != _capturedPieces.end(); ++itr)
    {
        score += ((Piece*)*itr)->value();
    }

    return score;
}

methods.moveTo:
bool RestrictedPiece::moveTo(Player& byPlayer, Square& to)
{
    bool validMove = Piece::moveTo(byPlayer, to);

    // only change _moved if a valid move is made 
    // and this piece hasn't already been moved
    if(validMove && !_moved)
    {
        _moved = true;
    }

    return validMove;
}

methods.canMoveTo:
bool King::canMoveTo(Square& location) const
{
    bool validMove = false;
    int translationX = location.getX() - this->location()->getX();
    int translationY = location.getY() - this->location()->getY();

    // valid move if moving 1 square forward/backwards
    if(abs(translationY) == 1 && translationX == 0)
    {
        validMove = true;
    }

    // valid move if moving 1 square sideways
    else if(abs(translationX) == 1 && translationY == 0)
    {
        validMove = true;
    }

    // valid move if moving 1 square diagonally
    else if(abs(translationX) == 1 && abs(translationY) == 1)
    {
        validMove = true;
    }

    return validMove;
}

bool Bishop::canMoveTo(Square& location) const
{
    bool validMove = false;

    // valid move if moving on a clear diagonal
    if(Board::getBoard()->isClearDiagonal(*(this->location()), location))
    {
        validMove = true;
    }

    return validMove;
}

methods.moveTo:
bool Pawn::moveTo(Player& byPlayer, Square& to)
{
    bool valid = false;

    // if the pawn has been promoted
    if(_delegate)
    {
        // use delegate piece's movement rules to determine validity
        valid = _delegate->moveTo(byPlayer, to);

        // if the move is valid, move the pawn:
        if(valid)
        {
            // unset the pawn's current square's occupant
            location()->setOccupier(NULL);

            // set this pawn's new location
            setLocation(&to);

            // set new square's occupant
            location()->setOccupier(this);
        }
    }
    else 
    {
        // otherwise, attempt to move normally as a pawn
        valid = RestrictedPiece::moveTo(byPlayer, to);

        // if the move is valid and the pawn has reached the 
        // opponent's edge of the board, promote the pawn to
        // a queen
        if(valid)
        {
            if(Board::getBoard()->isEndRow(*location()))
            {
                _delegate = new Queen(isWhite());
                _delegate->setLocation(location());
            }
        }
    }

    return valid;
}

methods.canMoveTo:
bool Pawn::canMoveTo(Square& location) const
{
    bool validMove = false;
    int translationX = location.getX() - this->location()->getX();
    int translationY = location.getY() - this->location()->getY();

    // if pawn has been promoted, use it's delegate's movement rules:
    if(_delegate)
    {
        validMove = _delegate->canMoveTo(location);
    }
    // otherwise, use normal pawn movement rules:
    else 
    {
        // ("forward" is "backwards" relative to the board for black pieces)
        if(!isWhite())
        {
            translationX *= -1;
            translationY *= -1;
        }

        // valid move if moving 1 square forward to unoccupied square
        if(!location.occupied() && translationY == 1 && translationX == 0)
        {
            validMove = true;
        }

        // valid move if !moved and moving 2 squares forward
        // to unoccupied square along a clear vertical
        else if(!hasMoved() && translationY == 2 && translationX == 0 &&
                Board::getBoard()->isClearVertical(*(this->location()), location))
        {
            validMove = true;
        }

        // valid move if capturing a piece on adjacent diagonal
        else if(location.occupied() && translationY == 1 && 
                (translationX == 1 || translationX == -1))
        {
            validMove = true;
        }        
    }

    return validMove;
}

