methods.canMoveTo:
bool Knight::canMoveTo(Square& location) const
{
    bool validMove = false;
    int translationX = location.getX() - this->location()->getX();
    int translationY = location.getY() - this->location()->getY();

    // valid move if moving 1 square forward/backwards
    // and 2 squares sideways
    if(abs(translationY) == 1 && abs(translationX) == 2)
    {
        validMove = true;
    }

    // valid move if moving 1 square sideways and 2 squares
    // forward/backwards
    else if(abs(translationX) == 1 && abs(translationY) == 2)
    {
        validMove = true;
    }

    return validMove;
}

bool Rook::canMoveTo(Square& location) const
{
    bool validMove = false;

    // valid move if moving on a clear vertical
    if(Board::getBoard()->isClearVertical(*(this->location()), location))
    {
        validMove = true;
    }

    // valid move if moving on a clear horizontal
    else if(Board::getBoard()->isClearHorizontal(*(this->location()), location))
    {
        validMove = true;
    }

    return validMove;
}

bool Queen::canMoveTo(Square& location) const
{
    bool validMove = false;

    // valid move if moving on a clear vertical
    if(Board::getBoard()->isClearVertical(*(this->location()), location))
    {
        validMove = true;
    }

    // valid move if moving on a clear horizontal
    else if(Board::getBoard()->isClearHorizontal(*(this->location()), location))
    {
        validMove = true;
    }

    // valid move if moving on a clear diagonal
    else if(Board::getBoard()->isClearDiagonal(*(this->location()), location))
    {
        validMove = true;
    }


    return validMove;
}
